-- Table: activity_logs
DROP TABLE IF EXISTS activity_logs CASCADE;
CREATE TABLE activity_logs (id integer DEFAULT nextval('activity_logs_id_seq'::regclass) NOT NULL, user_id integer, username character varying NOT NULL, action character varying NOT NULL, resource_type character varying NOT NULL, resource_id character varying, resource_name character varying, details jsonb, ip_address character varying, user_agent text, status character varying DEFAULT 'success'::character varying, error_message text, created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP);

