CREATE TABLE agentless_device_metrics (id integer DEFAULT nextval('agentless_device_metrics_id_seq'::regclass) NOT NULL, monitored_device_id integer, hostname character varying, cpu_usage double precision, memory_usage bigint, memory_total bigint, uptime bigint, status character varying, response_time integer, source character varying, collected_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP, created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP, dns_name character varying, disk_usage bigint, disk_total bigint);

