CREATE TABLE agentless_monitored_devices (id integer DEFAULT nextval('agentless_monitored_devices_id_seq'::regclass) NOT NULL, device_id uuid, ip_address character varying NOT NULL, hostname character varying, device_type character varying DEFAULT 'unknown'::character varying, snmp_enabled boolean DEFAULT false, snmp_version character varying DEFAULT '2c'::character varying, snmp_community character varying DEFAULT 'public'::character varying, ssh_enabled boolean DEFAULT false, ssh_user character varying, ssh_password character varying, ssh_key text, ssh_port integer DEFAULT 22, wmi_enabled boolean DEFAULT false, monitoring_enabled boolean DEFAULT true, last_check timestamp without time zone, status character varying DEFAULT 'unknown'::character varying, created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP, updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP);

