CREATE TABLE monitoring_alerts (id integer DEFAULT nextval('monitoring_alerts_id_seq'::regclass) NOT NULL, device_id integer, alert_type character varying NOT NULL, severity character varying DEFAULT 'warning'::character varying, message text NOT NULL, threshold_value double precision, current_value double precision, acknowledged boolean DEFAULT false, acknowledged_by character varying, acknowledged_at timestamp without time zone, resolved boolean DEFAULT false, resolved_at timestamp without time zone, created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP);

